Use ASP.NET Core's **`WebApplicationFactory<TEntryPoint>`** from `Microsoft.AspNetCore.Mvc.Testing`. It spins up your app in-memory with no real network listener, and gives you an `HttpClient` that talks to it directly.

**1. Add the NuGet package:**

```
dotnet add package Microsoft.AspNetCore.Mvc.Testing
```

**2. Write a test (xUnit example):**

```csharp
using System.Net.Http.Json;
using Microsoft.AspNetCore.Mvc.Testing;
using Xunit;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.Equal(1, body.GetProperty("id").GetInt32());
        Assert.True(body.GetProperty("result").TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        // Initialize first (stateful session via Mcp-Session-Id header)
        var init = new { jsonrpc = "2.0", id = 1, method = "initialize",
            @params = new { protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" } } };

        var initResp = await _client.PostAsJsonAsync("/mcp", init);
        var sessionId = initResp.Headers.GetValues("Mcp-Session-Id").First();

        // Now call tools/list with the session header
        var listReq = new HttpRequestMessage(HttpMethod.Post, "/mcp")
        {
            Content = JsonContent.Create(new
            {
                jsonrpc = "2.0", id = 2, method = "tools/list"
            })
        };
        listReq.Headers.Add("Mcp-Session-Id", sessionId);

        var resp = await _client.SendAsync(listReq);
        resp.EnsureSuccessStatusCode();

        var body = await resp.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }
}
```

**Key points:**

- **No port, no process** — `WebApplicationFactory` hosts your app in-process and routes requests through an in-memory transport.
- **`Program` must be visible** — add `<InternalsVisibleTo Include="YourTestProject" />` to your server's `.csproj`, or declare a partial `Program` class.
- **Override config** if needed via `factory.WithWebHostBuilder(b => b.ConfigureServices(...))` to swap dependencies (e.g., mock databases).
- **Session management** — if your server uses `Mcp-Session-Id`, capture it from the `initialize` response and send it on subsequent requests (as shown above).
- **SSE streaming** — for streaming responses, read the `HttpContent` as a stream and parse `text/event-stream` lines incrementally.
